<template>
    <div class="create-document-container">
        <DocumentTopNav :isPreview.sync="isPreview" @cancel="$router.push('/administration/documents')"
            @save="() => { }" />

        <!-- Main Content Area -->
        <CRow class="px-4">
            <!-- Editor Column -->
            <CCol md="9">
                <CCard class="toolbar-card mb-3 border-0 shadow-sm" v-if="!isPreview">
                    <CCardBody class="p-3">
                        <EditorToolbar @image-uploaded="handleToolbarImage"
                            @insert-text-block="handleInsertTextBlock" />
                    </CCardBody>
                </CCard>

                <div class="editor-workspace" ref="workspace">
                    <div class="document-editor-full" :class="{ 'preview-mode': isPreview }"
                         :style="{ transform: `scale(${editorScale})`, transformOrigin: 'top center' }">
                        <KonvaEditor ref="konvaEditor" :isPreview="isPreview" />
                    </div>
                </div>
            </CCol>

            <!-- Sidebar Column -->
            <CCol md="3">
                <DocumentSidebar :status.sync="status" :currentDate="currentDate" :currentTime="currentTime" />
            </CCol>
        </CRow>
    </div>
</template>

<script>
export default {
    name: 'CreateDocument',
    components: {
        KonvaEditor: () => import('../../../components/documents/KonvaEditor.vue'),
        DocumentTopNav: () => import('../../../components/documents/DocumentTopNav.vue'),
        EditorToolbar: () => import('../../../components/documents/EditorToolbar.vue'),
        DocumentSidebar: () => import('../../../components/documents/DocumentSidebar.vue')
    },
    data() {
        return {
            documentTitle: '',
            status: 'Draft',
            currentDate: '',
            currentTime: '',
            timer: null,
            isPreview: false,
            editorScale: 1
        }
    },
    mounted() {
        this.updateDateTime();
        this.timer = setInterval(this.updateDateTime, 1000);
        
        this.calculateScale();
        window.addEventListener('resize', this.calculateScale);
    },
    beforeDestroy() {
        if (this.timer) {
            clearInterval(this.timer);
        }
        window.removeEventListener('resize', this.calculateScale);
    },
    methods: {
        calculateScale() {
            const workspace = this.$refs.workspace;
            if (!workspace) return;
            // Get available width
            const availableWidth = workspace.clientWidth;
            // 210mm in pixels at 96 DPI is approx 794px
            const a4WidthPx = 794;

            if (availableWidth > 0 && availableWidth < a4WidthPx) {
                this.editorScale = availableWidth / a4WidthPx;
            } else {
                this.editorScale = 1;
            }

            // Adjust workspace height since CSS scale leaves physical space behind
            const editorEl = workspace.querySelector('.document-editor-full');
            if (editorEl) {
                // 297mm height is approx 1123px, plus margins (24px top/bottom)
                const a4ApparentHeight = 1123 + 48;
                workspace.style.minHeight = (a4ApparentHeight * this.editorScale) + 'px';
            }
        },
        handleToolbarImage(dataUrl) {
            if (this.$refs.konvaEditor && this.$refs.konvaEditor.addImage) {
                this.$refs.konvaEditor.addImage(dataUrl)
            }
        },
        handleInsertTextBlock() {
            if (this.$refs.konvaEditor && this.$refs.konvaEditor.addTextBlock) {
                this.$refs.konvaEditor.addTextBlock()
            }
        },
        setLink() {
            const url = window.prompt('URL', '')
            if (url === null) return
            // konva editor doesn't use link marks; implement if needed
        },
        updateDateTime() {
            const now = new Date();
            this.currentDate = now.toLocaleDateString('en-US', {
                month: 'numeric',
                day: 'numeric',
                year: 'numeric'
            });
            this.currentTime = now.toLocaleTimeString('en-US', {
                hour: 'numeric',
                minute: '2-digit',
                hour12: true
            });
        }
    }
}
</script>

<style scoped>
.create-document-container {
    background-color: #f9fafb;
}

/* A4 workspace to contain the scaled editor smoothly */
.editor-workspace {
    width: 100%;
    display: flex;
    justify-content: center;
    overflow: hidden; /* to prevent scrollbar when scaled */
}

/* A4 editor container (visual + print) */
.document-editor-full {
    width: 210mm;
    height: 297mm;
    /* fixed A4 height */
    max-width: 210mm;
    max-height: 297mm;
    margin: 24px auto;
    position: relative;
    box-sizing: border-box;
    background-color: white;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.06);
    overflow: auto;
    /* keep inner scrolling for content */
    resize: none;
    /* prevent CSS resize */
}

@page {
    size: A4;
    margin: 12mm;
}

/* Toolbar Improvements */
.tiptap-toolbar .toolbar-btn {
    background-color: transparent !important;
    border: none !important;
    color: #4b5563 !important;
    box-shadow: none !important;
    font-size: 15px;
    padding: 6px 10px;
}

.tiptap-toolbar .toolbar-btn.active {
    background-color: #f3f4f6 !important;
    color: #4f46e5 !important;
    border-radius: 6px;
}

.tiptap-toolbar .toolbar-btn:hover {
    background-color: #f3f4f6 !important;
    color: #111827 !important;
    border-radius: 6px;
}

.toolbar-divider {
    width: 1px;
    height: 24px;
    background-color: #e5e7eb;
    margin: 0 10px;
}

::v-deep .tiptap-toolbar .toolbar-dropdown .dropdown-toggle {
    background-color: transparent !important;
    border: none !important;
    color: #4b5563 !important;
    font-weight: 500;
    font-size: 14px;
    border-radius: 6px;
    padding: 6px 12px;
    box-shadow: none !important;
}

::v-deep .tiptap-toolbar .toolbar-dropdown .dropdown-toggle:hover {
    background-color: #f3f4f6 !important;
    color: #111827 !important;
}

.document-title-input {
    width: 100%;
    border: 2px solid #111827;
    padding: 10px 15px;
    font-size: 32px;
    font-weight: 700;
    color: #111827;
    outline: none;
    transition: border-color 0.2s;
    border-radius: 6px;
}

.document-title-input:focus {
    border-color: #3b82f6;
}

.document-title-input::placeholder {
    color: #d1d5db;
}

/* TipTap ProseMirror Styling */
::v-deep .ProseMirror {
    width: 100%;
    box-sizing: border-box;
    height: auto;
    /* make editor inner area match A4 inner size (page height minus vertical padding) */
    min-height: calc(297mm - 32mm);
    max-width: 100%;
    outline: none;
    font-size: 16px;
    line-height: 1.6;
    color: #4b5563;
    padding: 0;
    /* padding is handled by .document-editor-full */
    background: transparent;
}

/* Prevent wide content: wrap long words and constrain images to container width */
::v-deep .ProseMirror img {
    max-width: 100%;
    height: auto;
    display: block;
}

::v-deep .ProseMirror {
    word-break: break-word;
    overflow-wrap: break-word;
    white-space: normal;
}

::v-deep .ProseMirror pre,
::v-deep .ProseMirror code {
    white-space: pre-wrap;
}

.preview-mode ::v-deep .ProseMirror p.is-editor-empty:first-child::before {
    display: none;
}

.preview-mode .document-title-input {
    border-color: transparent !important;
    padding: 10px 0;
    pointer-events: none;
}

::v-deep .blue-variable {
    color: #3b82f6 !important;
    font-weight: 600;
    background-color: #eff6ff;
    padding: 0 4px;
    border-radius: 4px;
}
</style>
